import React from 'react';

function Trade(props) {


    return(
        <div>
            <table>
                <th>
                    <tr>
                        <td>ID</td>
                        <td>Stock</td>
                    </tr>
                </th>
            </table>
            {props.trade.stock}
            
            
        </div>
    )
}

export default Trade;
